const imovel = $('Sanity — Buscar dados do imóvel').item.json.result;
const webhookBody = $('Webhook — Receber ID do imóvel').item.json.body;

if (!imovel) throw new Error('Imóvel não encontrado: ' + webhookBody._id);

const tom = webhookBody.tom || 'sofisticado';
const focusSEO = webhookBody.focusSEO || `${imovel.tipo || 'imóvel'} ${imovel.finalidade?.toLowerCase() || 'à venda'} ${imovel.bairro?.nome || ''}`;

const tomsConfig = {
  sofisticado: 'Escreva em tom refinado e aspiracional, voltado para o público de alto padrão que valoriza exclusividade e estilo de vida.',
  direto: 'Escreva de forma objetiva e informativa, destacando os pontos fortes sem rodeios.',
  emocional: 'Escreva de forma envolvente, criando conexão emocional com o leitor e pintando um quadro vívido do cotidiano no imóvel.'
};

const detalhes = [
  imovel.tipo && `Tipo: ${imovel.tipo}`,
  imovel.finalidade && `Finalidade: ${imovel.finalidade}`,
  imovel.quartos && `${imovel.quartos} quartos${imovel.suites ? `, ${imovel.suites} suíte(s)` : ''}`,
  imovel.banheiros && `${imovel.banheiros} banheiro(s)`,
  imovel.vagas && `${imovel.vagas} vaga(s)`,
  imovel.areaUtil && `${imovel.areaUtil}m² úteis`,
  imovel.areaTotal && `${imovel.areaTotal}m² totais`,
  imovel.andar && `${imovel.andar}º andar`,
  imovel.bairro?.nome && `Bairro: ${imovel.bairro.nome}`,
  imovel.condominio?.nome && `Condomínio: ${imovel.condominio.nome}`,
  imovel.preco && `Preço: R$ ${imovel.preco.toLocaleString('pt-BR')}`,
].filter(Boolean).join('\n');

const prompt = `Você é um especialista em copywriting imobiliário de luxo para o mercado do Rio de Janeiro.

${tomsConfig[tom]}

Crie uma descrição completa para o anúncio imobiliário abaixo. A descrição deve:
- Ter entre 180 e 280 palavras
- Ser otimizada para SEO com foco na keyword: "${focusSEO}"
- Mencionar os diferenciais do imóvel e da localização
- Terminar com uma chamada para ação discreta
- Ser escrita em português brasileiro
- NÃO incluir preço
- NÃO usar bullet points

Dados do imóvel:
${detalhes}

Descrição existente (para contexto, mas reescreva completamente):
${imovel.descricao || '(sem descrição ainda)'}

Retorne APENAS o texto da descrição, sem título, sem metadados.`;

return [{ json: { prompt, imovelId: imovel._id, tom, focusSEO } }];

const resposta = $input.first().json;
const descricaoGerada = resposta.choices?.[0]?.message?.content?.trim() || '';
const imovelId = $('Montar prompt para IA').item.json.imovelId;

if (!descricaoGerada) throw new Error('IA não retornou descrição');

return [{ json: { descricaoGerada, imovelId } }];
